```
int n, m;
векторска<вектор<int>> мрежа;
вектор<vector<bool>> посетен;

void dfs(int x, int y, int остров) {
    ако (x < 0 || y < 0 || x >= n || y >= m) се врати;
    ако (мрежа[x][y] == 0 || посетено[x][y]) се врати;
    посетено[x][y] = точно;
    мрежа[x][y] = остров;
    dfs(x, y + 1, остров);
    dfs (x + 1, y, остров);
    dfs (x - 1, y, остров);
    dfs (x, y - 1, остров);
}

